mapper.select:
/* VacationMapper.countActiveVacationPerson: 활성 휴가자 존재 여부 조회 */
SELECT COUNT(1)
  FROM PERSON
 WHERE PERSON_SEQ = #{personSeq}
   AND DEL_YN = 'N'

/* VacationMapper.countVacationCompany: 휴가 사용 가능 회사 존재 여부 조회 */
SELECT COUNT(1)
  FROM WORK_COMPANY_INFO
 WHERE WORK_COMPANY_SEQ = #{workCompanySeq}
   AND VACATION_LIMIT_CNT >= 1

/* VacationMapper.getDefaultVacationCompanySeq: 휴가가 존재하는 회사 중 기본 선택할 회사 번호 조회 */ SELECT C.WORK_COMPANY_SEQ FROM VACATION V JOIN PERSON P ON P.PERSON_SEQ = V.PERSON_SEQ AND P.DEL_YN = 'N' JOIN WORK_COMPANY_INFO C ON C.WORK_COMPANY_SEQ = V.WORK_COMPANY_SEQ AND C.VACATION_LIMIT_CNT >= 1 WHERE V.DEL_YN = 'N'
AND P.PERSON_SEQ = #{personSeq}
GROUP BY C.WORK_COMPANY_SEQ , C.DISP_ORD ORDER BY C.DISP_ORD ASC , C.WORK_COMPANY_SEQ ASC LIMIT 1

/* VacationMapper.getVacationFilterCompanyList: 휴가 등록 이력이 있는 회사 필터 목록 조회 */ SELECT C.WORK_COMPANY_SEQ , C.WORK_COMPANY_NM , C.WORK_PLATFORM_NM , C.VACATION_LIMIT_CNT , C.DISP_ORD FROM VACATION V JOIN PERSON P ON P.PERSON_SEQ = V.PERSON_SEQ AND P.DEL_YN = 'N' JOIN WORK_COMPANY_INFO C ON C.WORK_COMPANY_SEQ = V.WORK_COMPANY_SEQ AND C.VACATION_LIMIT_CNT >= 1 WHERE V.DEL_YN = 'N'
AND P.PERSON_SEQ = #{personSeq}
GROUP BY C.WORK_COMPANY_SEQ , C.WORK_COMPANY_NM , C.WORK_PLATFORM_NM , C.VACATION_LIMIT_CNT , C.DISP_ORD ORDER BY C.DISP_ORD ASC , C.WORK_COMPANY_SEQ ASC

mapper.insert:
/* VacationMapper.insertVacation: 휴가 사용 정보 저장 */
INSERT INTO VACATION (
       WORK_COMPANY_SEQ
     , PERSON_SEQ
     , VACATION_CD
     , START_DT
     , END_DT
     , VACATION_MEMO
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{workCompanySeq}
     , #{personSeq}
     , #{vacationCd}
     , STR_TO_DATE(#{startDt}, '%Y-%m-%d')
     , STR_TO_DATE(#{endDt}, '%Y-%m-%d')
     , #{vacationMemo}
     , 'N'
     , #{regNo}
     , #{udtNo}
)
